clc;
clear;
close all;

N = 20;
h = 1/N;

x = linspace(0,1,N+1);

u_exact = 0.5*x.^2;

u_num = zeros(1,N+1);
u_num(1) = 0;

for i = 1:N
    u_num(i+1) = u_num(i) + h*x(i);
end

error = abs(u_exact - u_num);

fprintf('      x\t\tNumerical\tExact\t\tError\n'); %[output:5eed0877]
for i = 1:length(x) %[output:group:6b827bb5]
    fprintf('%0.4f\t\t%0.6f\t%0.6f\t%0.6f\n', ... %[output:8f6bed65]
            x(i), u_num(i), u_exact(i), error(i)); %[output:8f6bed65]
end %[output:group:6b827bb5]

figure; %[output:1f5717df]
plot(x,u_exact,'LineWidth',2); %[output:1f5717df]
hold on; %[output:1f5717df]
plot(x,u_num,'o--','LineWidth',1.5); %[output:1f5717df]
grid on; %[output:1f5717df]
xlabel('x'); %[output:1f5717df]
ylabel('u(x)'); %[output:1f5717df]
title('Analytical vs Numerical Solution'); %[output:1f5717df]
legend('Analytical','FDM'); %[output:1f5717df]
saveas(gcf,'comparison_plot.png') %[output:1f5717df]

figure; %[output:683dd340]
plot(x,error,'o-','LineWidth',1.5); %[output:683dd340]
grid on; %[output:683dd340]
xlabel('x'); %[output:683dd340]
ylabel('Absolute Error'); %[output:683dd340]
title('Error Distribution'); %[output:683dd340]
saveas(gcf,'error_plot.png') %[output:683dd340]

fprintf('\nMaximum Error = %e\n', max(error)); %[output:0c914a7a]

